mapper.select:
SELECT a.*, b.brand_name AS brandName, c.realname AS businessName FROM merchant_info a LEFT JOIN kol_brand b ON a.brand_id = b.id LEFT JOIN sys_user c ON a.business_id = c.id WHERE 1 = 1
and a.business_id = #{merchantInfo.businessId}
and a.brand_id = #{merchantInfo.brandId}
and a.customer_level = #{merchantInfo.customerLevel}
and a.customer_acquisition_method like CONCAT('%', #{merchantInfo.customerAcquisitionMethod}, '%')
and a.main_products like CONCAT('%', #{merchantInfo.mainProducts}, '%')
and a.company_name like CONCAT('%', #{merchantInfo.companyName}, '%')
and a.address like CONCAT('%', #{merchantInfo.address}, '%')
and a.brand_contact_person like CONCAT('%', #{merchantInfo.brandContactPerson}, '%')
and a.cooperation_status = #{merchantInfo.cooperationStatus}
and (a.phone like CONCAT('%', #{merchantInfo.keyword}, '%') or a.wechat_id like CONCAT('%', #{merchantInfo.keyword}, '%') or a.feishu_id like CONCAT('%', #{merchantInfo.keyword},'%') or a.email like CONCAT('%', #{merchantInfo.keyword}, '%') or a.business_wechat like CONCAT('%', #{merchantInfo.keyword}, '%') or a.business_feishu like CONCAT('%', #{merchantInfo.keyword}, '%') or a.business_phone like CONCAT('%', #{merchantInfo.keyword}, '%') )
